import requests

def trace_redirects(url):
    history = [url]

    while True:
        try:
            resp = requests.get(url)

            if resp.is_redirect:
                try:
                    url = resp.headers['Location']
                    url = '/' + url if url.endswith('/') else url
                    history.append(url)
                except KeyError:
                    history.append(url)
            else:
                break
        except requests.RequestException:
            break

    if 'redirect_url' in history:
        print('Redirect followed to', history[-1])
    else:
        print('No redirects detected')

